   237→static void write_table_section(Context* ctx,
   238→                                const SectionPtrVector& sections) {
   239→  /* Total section size includes the element count leb128 which is
   240→   * always 1 in the current spec */
   241→  Index table_count = 1;
   242→  uint32_t flags = WABT_BINARY_LIMITS_HAS_MAX_FLAG;
   243→  Index elem_count = 0;
   244→
   245→  for (Section* section: sections) {
   246→    elem_count += section->binary->table_elem_count;
   247→  }
   248→
   249→  Stream* stream = &ctx->stream;
   250→  WRITE_UNKNOWN_SIZE(stream);
   251→  write_u32_leb128(stream, table_count, "table count");
   252→  write_type(stream, Type::Anyfunc);
   253→  write_u32_leb128(stream, flags, "table elem flags");
   254→  write_u32_leb128(stream, elem_count, "table initial length");
   255→  write_u32_leb128(stream, elem_count, "table max length");
   256→  FIXUP_SIZE(stream);
   257→}
   258→
   259→static void write_export_section(Context* ctx) {
   260→  Index total_exports = 0;
   261→  for (const std::unique_ptr<LinkerInputBinary>& binary: ctx->inputs) {
   262→    total_exports += binary->exports.size();
   263→  }
   264→
   265→  Stream* stream = &ctx->stream;
   266→  WRITE_UNKNOWN_SIZE(stream);
   267→  write_u32_leb128(stream, total_exports, "export count");
   268→
   269→  for (const std::unique_ptr<LinkerInputBinary>& binary : ctx->inputs) {
   270→    for (const Export& export_ : binary->exports) {
   271→      write_slice(stream, export_.name, "export name");
   272→      stream->WriteU8Enum(export_.kind, "export kind");
   273→      Index index = export_.index;
   274→      switch (export_.kind) {
   275→        case ExternalKind::Func:
   276→          index = binary->RelocateFuncIndex(index);
   277→          break;
   278→        default:
   279→          WABT_FATAL("unsupport export type: %d\n",
   280→                     static_cast<int>(export_.kind));
   281→          break;
   282→      }
   283→      write_u32_leb128(stream, index, "export index");
   284→    }
   285→  }
   286→  FIXUP_SIZE(stream);
   287→}
   288→
   289→static void write_elem_section(Context* ctx,
   290→                               const SectionPtrVector& sections) {
   291→  Stream* stream = &ctx->stream;
   292→  WRITE_UNKNOWN_SIZE(stream);
   293→
   294→  Index total_elem_count = 0;
   295→  for (Section* section : sections) {
   296→    total_elem_count += section->binary->table_elem_count;
   297→  }
   298→
   299→  write_u32_leb128(stream, 1, "segment count");
   300→  write_u32_leb128(stream, 0, "table index");
   301→  write_opcode(&ctx->stream, Opcode::I32Const);
   302→  write_i32_leb128(&ctx->stream, 0, "elem init literal");
   303→  write_opcode(&ctx->stream, Opcode::End);
   304→  write_u32_leb128(stream, total_elem_count, "num elements");
   305→
   306→  ctx->current_section_payload_offset = stream->offset();
   307→
   308→  for (Section* section : sections) {
   309→    apply_relocations(section);
   310→    write_section_payload(ctx, section);
