   339→  write_slice(&ctx->stream, import->module_name, "import module name");
   340→  write_slice(&ctx->stream, import->name, "import field name");
   341→  ctx->stream.WriteU8Enum(ExternalKind::Func, "import kind");
   342→  write_u32_leb128(&ctx->stream, import->sig_index + offset,
   343→                   "import signature index");
   344→}
