    84→  FILE* infile = fopen(filename, "rb");
    85→  if (!infile) {
    86→    const char format[] = "unable to read file %s";
    87→    char msg[PATH_MAX + sizeof(format)];
    88→    wabt_snprintf(msg, sizeof(msg), format, filename);
    89→    perror(msg);
    90→    return Result::Error;
    91→  }
    92→
    93→  if (fseek(infile, 0, SEEK_END) < 0) {
    94→    perror("fseek to end failed");
    95→    return Result::Error;
    96→  }
    97→
